// ADR-2: stateless render token = base64(ts.nonce.HMAC_SHA256(secret, ts.nonce)).
// Requires NODE_FUNCTION_ALLOW_BUILTIN=crypto and WGC_HMAC_SECRET in the environment.
const crypto = require('crypto');
const secret = $env.WGC_HMAC_SECRET;
if (!secret) throw new Error('WGC_HMAC_SECRET is not set'); // fail loud, never issue unsigned tokens
const ts = String(Date.now());
const nonce = crypto.randomBytes(8).toString('hex');
const mac = crypto.createHmac('sha256', secret).update(ts + '.' + nonce).digest('hex');
const token = Buffer.from(ts + '.' + nonce + '.' + mac, 'utf8').toString('base64');
return [{ json: { token } }];
